      wechat_group: '微信群', whatsapp_group: 'WhatsApp群', linkedin: 'LinkedIn', phone: '电话',
      offline: '线下拜访', visit: '线下拜访', manual_sales: '人工销售', automation: '自动化', preference: '按客户偏好',
