        return '<article><strong>' + esc(userName) + '</strong><span>本次 ' + esc(bucket.items.length) + ' 条 · 渠道：' + esc(bucket.channels.join('、') || '-').replace(/wechat|weixin/g, '微信') + '</span></article>';
