    if (!root.children.length) {
      var empty = document.createElement('section');
      empty.className = 'action_section action_empty';
      empty.innerHTML = '<h3>暂无可执行操作</h3><p>该模块仍是展示/框架状态，未接入真实业务前不显示假按钮。</p>';
      root.appendChild(empty);
    }
